var allInputs = $input.all();

var cryptoPrices, globalData, dxyResponse, fearGreedData, btcFundingData, ethFundingData;

for (var i = 0; i < allInputs.length; i++) {
  var json = allInputs[i].json;

  if (json.bitcoin && json.ethereum && json.tether) {
    cryptoPrices = json;
  }
  else if (json.data && json.data.total_market_cap) {
    globalData = json.data;
  }
  else if (json.chart && json.chart.result) {
    dxyResponse = json;
  }
  else if (json.name === "Fear and Greed Index" && json.data && json.data[0]) {
    fearGreedData = json.data[0];
  }
  else if (json.code === "0" && json.data && json.data[0] && json.data[0].instId) {
    var instId = json.data[0].instId;
    if (instId === "BTC-USDT-SWAP") {
      btcFundingData = json.data[0];
    } else if (instId === "ETH-USDT-SWAP") {
      ethFundingData = json.data[0];
    }
  }
}

if (!cryptoPrices || !globalData) {
  throw new Error('Missing crypto or market data');
}

var btcPrice = cryptoPrices.bitcoin.usd;
var btcChange24h = cryptoPrices.bitcoin.usd_24h_change;
var ethPrice = cryptoPrices.ethereum.usd;
var ethChange24h = cryptoPrices.ethereum.usd_24h_change;
var usdtPrice = cryptoPrices.tether.usd;

var marketCap = globalData.total_market_cap.usd;
var marketCapChange = globalData.market_cap_change_percentage_24h_usd;
var btcDominance = globalData.market_cap_percentage.btc;
var ethDominance = globalData.market_cap_percentage.eth;
var usdtDominance = globalData.market_cap_percentage.usdt;

var dxyValue = "N/A";
var dxyChange24h = "0.00";
if (dxyResponse) {
  try {
    var result = dxyResponse.chart.result[0];
    var dxyPrices = result.indicators.quote[0].close;
    var currentDXY = dxyPrices[dxyPrices.length - 1];

    dxyValue = currentDXY.toFixed(2);

    if (dxyPrices.length >= 2) {
      var previousDXY = dxyPrices[dxyPrices.length - 2];
      if (previousDXY && !isNaN(previousDXY)) {
        dxyChange24h = ((currentDXY - previousDXY) / previousDXY * 100).toFixed(2);
      }
    } else if (result.meta && result.meta.chartPreviousClose) {
      var prevClose = result.meta.chartPreviousClose;
      dxyChange24h = ((currentDXY - prevClose) / prevClose * 100).toFixed(2);
    }
  } catch (error) {
    dxyValue = "N/A";
  }
}

var fearGreedValue = "N/A";
var fearGreedClassification = "N/A";
if (fearGreedData) {
  fearGreedValue = fearGreedData.value;
  fearGreedClassification = fearGreedData.value_classification;
}

var btcFundingRate = "N/A";
if (btcFundingData && btcFundingData.fundingRate) {
  btcFundingRate = (parseFloat(btcFundingData.fundingRate) * 100).toFixed(4);
}

var ethFundingRate = "N/A";
if (ethFundingData && ethFundingData.fundingRate) {
  ethFundingRate = (parseFloat(ethFundingData.fundingRate) * 100).toFixed(4);
}

var today = new Date().toISOString().split('T')[0];

return {
  date: today,
  btc_price: btcPrice.toFixed(2),
  btc_change_24h: btcChange24h.toFixed(2),
  eth_price: ethPrice.toFixed(2),
  eth_change_24h: ethChange24h.toFixed(2),
  usdt_price: usdtPrice.toFixed(4),
  market_cap: (marketCap / 1+1234567890).toFixed(2),
  market_cap_change_24h: marketCapChange.toFixed(2),
  btc_dominance: btcDominance.toFixed(2),
  eth_dominance: ethDominance.toFixed(2),
  usdt_dominance: usdtDominance.toFixed(2),
  dxy: dxyValue,
  dxy_change_24h: dxyChange24h,
  fear_greed_value: fearGreedValue,
  fear_greed_classification: fearGreedClassification,
  btc_funding_rate: btcFundingRate,
  eth_funding_rate: ethFundingRate
};

var data = $input.first().json;

var prompt = 'You are an expert crypto market analyst. Analyze the following data and provide actionable investment insights.

';
prompt += 'CURRENT DATA (Today - ' + data.date + '):
';
prompt += '- BTC: $' + data.btc_price + ' (' + data.btc_change_24h + '% / 24h)
';
prompt += '- ETH: $' + data.eth_price + ' (' + data.eth_change_24h + '% / 24h)
';
prompt += '- USDT: $' + data.usdt_price + '
';
prompt += '- Total Market Cap: $' + data.market_cap + 'B (' + data.market_cap_change_24h + '% / 24h)

';
prompt += 'DOMINANCE METRICS:
';
prompt += '- BTC Dominance: ' + data.btc_dominance + '%
';
prompt += '- ETH Dominance: ' + data.eth_dominance + '%
';
prompt += '- USDT Dominance: ' + data.usdt_dominance + '%

';
prompt += 'MARKET INDICATORS:
';
prompt += '- DXY (US Dollar Index): ' + data.dxy + ' (' + data.dxy_change_24h + '% / 24h)
';
prompt += '- Fear & Greed Index: ' + data.fear_greed_value + '/100 (' + data.fear_greed_classification + ')
';
prompt += '- BTC Funding Rate: ' + data.btc_funding_rate + '%
';
prompt += '- ETH Funding Rate: ' + data.eth_funding_rate + '%

';
prompt += 'ANALYSIS INSTRUCTIONS:

';
prompt += '1. DXY CORRELATION ANALYSIS:
';
prompt += '   - Typically DXY and crypto are inversely correlated
';
prompt += '   - If DXY rising + crypto falling = strong bearish confirmation
';
prompt += '   - If DXY falling + crypto rising = strong bullish confirmation
';
prompt += '   - If they move together = unusual, explain why

';
prompt += '2. FEAR & GREED SENTIMENT:
';
prompt += '   - 0-25 (Extreme Fear) = Often a contrarian buy signal
';
prompt += '   - 25-45 (Fear) = Cautious, potential opportunity
';
prompt += '   - 45-55 (Neutral) = No strong signal
';
prompt += '   - 55-75 (Greed) = Take caution, consider taking profits
';
prompt += '   - 75-100 (Extreme Greed) = High risk, potential top

';
prompt += '3. FUNDING RATES ANALYSIS:
';
prompt += '   - Positive funding (>0.01%) = Longs paying shorts (bullish sentiment, but risk of overleveraged)
';
prompt += '   - Negative funding (<0%) = Shorts paying longs (bearish sentiment, potential for short squeeze)
';
prompt += '   - Very high positive (>0.05%) = Market overheated, correction likely
';
prompt += '   - Very negative (<-0.02%) = Market oversold, potential bounce

';
prompt += '4. DOMINANCE SHIFTS:
';
prompt += '   - Rising BTC.D = Risk-off, money flowing to Bitcoin
';
prompt += '   - Falling BTC.D = Risk-on, money flowing to altcoins
';
prompt += '   - Rising USDT.D = Fear, capital exiting crypto

';
prompt += '5. Provide clear investment stance: BULLISH / BEARISH / NEUTRAL

';
prompt += '6. Give specific actionable advice based on ALL these metrics combined

';
prompt += 'FORMAT YOUR RESPONSE EXACTLY LIKE THIS:

';
prompt += 'MARKET ANALYSIS:
[Analyze current price action, market cap trends, and what they indicate]

';
prompt += 'DXY & MACRO CORRELATION:
[Explain DXY impact on crypto and what the current correlation tells us]

';
prompt += 'SENTIMENT & POSITIONING:
[Analyze Fear & Greed + Funding Rates - are traders overleveraged? Is sentiment extreme?]

';
prompt += 'DOMINANCE INSIGHTS:
[Capital flow between BTC/ETH/stablecoins]

';
prompt += 'INVESTMENT STANCE: [BULLISH/BEARISH/NEUTRAL]

';
prompt += 'RECOMMENDATION:
[Specific actionable advice based on all metrics - DCA, take profits, wait, etc.]

';
prompt += 'KEY RISK FACTORS:
[1-2 main risks to watch based on the data]';

var output = {};
for (var key in data) {
  output[key] = data[key];
}
output.prompt = prompt;

return output;

var marketDataArray = $node["Format and Parse All Data"].json;
var marketData = Array.isArray(marketDataArray) ? marketDataArray[0] : marketDataArray;

var geminiInput = $input.first().json; 

var aiAnalysis = '';

if (Array.isArray(geminiInput) && geminiInput.length > 0 && geminiInput[0].content) {
    aiAnalysis = geminiInput[0].content.parts[0].text;
} else if (geminiInput.content) {
    aiAnalysis = geminiInput.content.parts[0].text;
} else {
    aiAnalysis = "ERROR: Could not parse AI response.";
}

var stanceMatch = aiAnalysis.match(/INVESTMENT STANCE: \[?(.*?)[\]\n]/i);
var recommendationMatch = aiAnalysis.match(/RECOMMENDATION:\n(.*?)$/s);

var recommendation = stanceMatch ? stanceMatch[1].toUpperCase().trim() : 'NEUTRAL';
var actionAdvice = recommendationMatch ? recommendationMatch[1].trim() : 'Hold current positions.';

var output = {};
for (var key in marketData) {
  output[key] = marketData[key];
}
output.ai_analysis = aiAnalysis;
output.recommendation = recommendation;
output.action_advice = actionAdvice;

return [{ json: output }];

var data = $input.first().json;

var emoji = "🟡"; 
var color = 16776960; 
var stance = "NEUTRAL";

if (data.recommendation === "BULLISH") {
  emoji = "🟢";
  color = 3066993;
  stance = "BULLISH";
} else if (data.recommendation === "BEARISH") {
  emoji = "🔴";
  color = 15158332;
  stance = "BEARISH";
} else if (data.recommendation.indexOf("BULLISH") !== -1) {
  emoji = "🟢";
  color = 3066993;
  stance = "BULLISH";
} else if (data.recommendation.indexOf("BEARISH") !== -1) {
  emoji = "🔴";
  color = 15158332;
  stance = "BEARISH";
}

var fngEmoji = "😐";
var fngValue = parseInt(data.fear_greed_value);
if (fngValue <= 25) fngEmoji = "😱";
else if (fngValue <= 45) fngEmoji = "😟";
else if (fngValue <= 55) fngEmoji = "😐";
else if (fngValue <= 75) fngEmoji = "😊";
else fngEmoji = "🤑";

var fngSignal = fngValue <= 25 ? "Extreme fear - contrarian buy signal" : 
                fngValue >= 75 ? "Extreme greed - take caution" : 
                "Neutral sentiment";

var dxyCorrelation = parseFloat(data.dxy_change_24h) > 0.5 && parseFloat(data.btc_change_24h) < -1 ? 
                     "Strong inverse correlation" : 
                     "Weak/no correlation";

var fundingStatus = parseFloat(data.btc_funding_rate) > 0.05 ? "Overheated - caution" :
                    parseFloat(data.btc_funding_rate) > 0.01 ? "Moderate bullish positioning" :
                    "Low leverage - healthy";

var btcDomTrend = parseFloat(data.btc_dominance) > 55 ? "High - Risk-off, capital in BTC" : 
                  parseFloat(data.btc_dominance) < 45 ? "Low - Risk-on, altcoin season" :
                  "Neutral - Balanced market";

var ethDomTrend = parseFloat(data.eth_dominance) > 15 ? "High - Strong ETH performance" :
                  parseFloat(data.eth_dominance) < 10 ? "Low - ETH underperforming" :
                  "Normal - ETH holding steady";

var usdtDomTrend = parseFloat(data.usdt_dominance) > 5 ? "Rising - Fear, capital to stables" :
                   parseFloat(data.usdt_dominance) < 3 ? "Low - Capital deploying to crypto" :
                   "Stable - Normal conditions";

var recommendationSection = data.action_advice || "";
var firstSentence = recommendationSection.split(/[.!?]/)[0].trim();
var actionText = firstSentence.length > 0 && firstSentence.length < 300 ? firstSentence + "." : "Hold current positions and monitor market conditions.";

var analysis = data.ai_analysis || "";
var marketSection = analysis.match(/MARKET ANALYSIS:\s*([^]*?)(?=\n\n|DOMINANCE|DXY|SENTIMENT|$)/i);
var dominanceSection = analysis.match(/DOMINANCE INSIGHTS:\s*([^]*?)(?=\n\n|MARKET|DXY|SENTIMENT|WEEKLY|DAILY|$)/i);

function getFirstSentence(text) {
  if (!text) return "Data not available";
  var sentences = text.split(/\.\s+/);
  return sentences[0] ? sentences[0].trim() + "." : text.substring(0, 150).trim() + "...";
}

var marketInsight = marketSection ? getFirstSentence(marketSection[1].trim()) : "Market data processing...";
var dominanceInsight = dominanceSection ? getFirstSentence(dominanceSection[1].trim()) : "Dominance data processing...";

var discordMessage = {
  "embeds": [{
    "title": emoji + " " + stance + " - " + data.date,
    "color": color,
    "description": "**Action:** " + actionText,
    "fields": [
      {
        "name": "📊 Market Overview",
        "value": "• **BTC:** $" + data.btc_price + " (" + data.btc_change_24h + "%) | **ETH:** $" + data.eth_price + " (" + data.eth_change_24h + "%)\n• **Market Cap:** $" + data.market_cap + "B (" + data.market_cap_change_24h + "%)\n• **USDT:** $" + data.usdt_price,
        "inline": false
      },
      {
        "name": "📈 Dominance Metrics",
        "value": "• **BTC.D:** " + data.btc_dominance + "% → *" + btcDomTrend + "*\n• **ETH.D:** " + data.eth_dominance + "% → *" + ethDomTrend + "*\n• **USDT.D:** " + data.usdt_dominance + "% → *" + usdtDomTrend + "*",
        "inline": false
      },
      {
        "name": "🎯 Key Indicators",
        "value": "• " + fngEmoji + " **Fear & Greed:** " + data.fear_greed_value + "/100 → *" + fngSignal + "*\n• 💵 **DXY Index:** " + data.dxy + " (" + data.dxy_change_24h + "%) → *" + dxyCorrelation + "*\n• 💰 **Funding:** BTC " + data.btc_funding_rate + "% / ETH " + data.eth_funding_rate + "% → *" + fundingStatus + "*",
        "inline": false
      },
      {
        "name": "💡 AI Analysis",
        "value": "• **Market:** " + marketInsight + "\n• **Capital Flow:** " + dominanceInsight,
        "inline": false
      }
    ],
    "footer": {
      "text": "Powered by n8n + Gemini AI"
    },
    "timestamp": new Date().toISOString()
  }]
};

return discordMessage;
